BEGIN;
INSERT INTO retail.retail_platforms(platform_code,platform_name,base_url,access_type,status,priority_rank,is_purchase_supported,is_data_collection_supported,robots_policy_url,terms_url,governance_notes)
VALUES('target','Target','https://www.target.com','authorized_scraper','active',20,true,true,'https://www.target.com/robots.txt','https://www.target.com/c/terms-conditions/-/N-4sr7l','Bright Data Target dataset primary collector with authorized Web Unlocker fallback using tcds_web_unlocker and tcds_premium_unlocker.') ON CONFLICT(platform_code) DO UPDATE SET platform_name=EXCLUDED.platform_name,base_url=EXCLUDED.base_url,access_type=EXCLUDED.access_type,status=EXCLUDED.status,governance_notes=EXCLUDED.governance_notes,updated_at=now();
ALTER TABLE retail.raw_product_captures ADD COLUMN IF NOT EXISTS source_platform text; UPDATE retail.raw_product_captures r SET source_platform=p.platform_code FROM retail.retail_platforms p WHERE r.platform_id=p.id AND r.source_platform IS NULL; ALTER TABLE retail.raw_product_captures ALTER COLUMN source_platform SET DEFAULT 'unknown';
CREATE INDEX IF NOT EXISTS ix_raw_product_captures_source_platform_captured ON retail.raw_product_captures(source_platform,captured_at DESC);
CREATE TABLE IF NOT EXISTS retail.ingest_dead_letters(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),platform_id uuid REFERENCES retail.retail_platforms(id),collection_run_id uuid REFERENCES retail.collection_runs(id),source_platform text NOT NULL,payload_hash text NOT NULL,raw_payload jsonb NOT NULL,error_code text NOT NULL,error_message text NOT NULL,attempt_count integer NOT NULL DEFAULT 1 CHECK(attempt_count>=1),status text NOT NULL DEFAULT 'pending' CHECK(status IN('pending','retrying','resolved','abandoned')),first_failed_at timestamptz NOT NULL DEFAULT now(),last_failed_at timestamptz NOT NULL DEFAULT now(),next_retry_at timestamptz,resolved_at timestamptz,resolution_notes text,UNIQUE(source_platform,payload_hash));
CREATE INDEX IF NOT EXISTS ix_ingest_dlq_retry ON retail.ingest_dead_letters(status,next_retry_at) WHERE status IN('pending','retrying');
CREATE TABLE IF NOT EXISTS retail.target_product_parsed(
 id uuid PRIMARY KEY DEFAULT gen_random_uuid(),raw_capture_id uuid NOT NULL UNIQUE REFERENCES retail.raw_product_captures(id),collection_run_id uuid REFERENCES retail.collection_runs(id),platform_id uuid NOT NULL REFERENCES retail.retail_platforms(id),source_platform text NOT NULL DEFAULT 'target' CHECK(source_platform='target'),
 product_id text NOT NULL,tcin_id text,dpci text,upc text,url text NOT NULL,title text NOT NULL,normalized_title text GENERATED ALWAYS AS(lower(btrim(title))) STORED,product_description text,brand text,normalized_brand text GENERATED ALWAYS AS(lower(btrim(brand))) STORED,
 initial_price numeric(14,2),sale_price numeric(14,2),final_price numeric(14,2),effective_price numeric(14,2) NOT NULL CHECK(effective_price>=0),currency_code char(3) NOT NULL DEFAULT 'USD',availability text,availability_text text,is_available boolean,
 rating numeric(3,2) CHECK(rating IS NULL OR rating BETWEEN 0 AND 5),reviews_count integer CHECK(reviews_count IS NULL OR reviews_count>=0),image_url text,images jsonb NOT NULL DEFAULT '[]',breadcrumbs jsonb NOT NULL DEFAULT '[]',breadcrumb_text text,seller_name text,promotion_fulltext text,
 offers jsonb,price_range jsonb,product_specifications jsonb NOT NULL DEFAULT '[]',shipping_returns_policy jsonb NOT NULL DEFAULT '[]',related_categories jsonb NOT NULL DEFAULT '[]',amount_of_stars jsonb NOT NULL DEFAULT '[]',recommendations jsonb NOT NULL DEFAULT '[]',variations jsonb NOT NULL DEFAULT '[]',what_customers_said jsonb NOT NULL DEFAULT '[]',review_images jsonb NOT NULL DEFAULT '[]',manufacturer_description jsonb,product_variant jsonb NOT NULL DEFAULT '[]',listing_has_variations boolean NOT NULL DEFAULT false,variant_attributes jsonb NOT NULL DEFAULT '[]',variants jsonb NOT NULL DEFAULT '[]',category_urls jsonb NOT NULL DEFAULT '[]',return_policy text,return_window integer,target_countries jsonb NOT NULL DEFAULT '[]',store_country text,
 source_dataset text NOT NULL DEFAULT 'brightdata_target',parser_version text NOT NULL DEFAULT 'brightdata_target_v1',parsed_payload jsonb NOT NULL,payload_hash text NOT NULL,parsed_at timestamptz NOT NULL DEFAULT now(),created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE(platform_id,product_id,payload_hash));
CREATE INDEX IF NOT EXISTS ix_target_tcin_latest ON retail.target_product_parsed(tcin_id,parsed_at DESC);CREATE INDEX IF NOT EXISTS ix_target_upc ON retail.target_product_parsed(upc) WHERE upc IS NOT NULL;CREATE INDEX IF NOT EXISTS ix_target_price_available ON retail.target_product_parsed(effective_price,is_available);CREATE INDEX IF NOT EXISTS ix_target_brand_title ON retail.target_product_parsed(normalized_brand,normalized_title);CREATE INDEX IF NOT EXISTS ix_target_payload_gin ON retail.target_product_parsed USING gin(parsed_payload);
CREATE TABLE IF NOT EXISTS retail.target_product_images(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),target_parsed_id uuid NOT NULL REFERENCES retail.target_product_parsed(id) ON DELETE CASCADE,image_url text NOT NULL,image_rank integer NOT NULL CHECK(image_rank>=1),is_main boolean NOT NULL DEFAULT false,created_at timestamptz NOT NULL DEFAULT now(),UNIQUE(target_parsed_id,image_url));
CREATE TABLE IF NOT EXISTS retail.target_product_specifications(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),target_parsed_id uuid NOT NULL REFERENCES retail.target_product_parsed(id) ON DELETE CASCADE,specification_name text NOT NULL,specification_value text,normalized_specification_name text GENERATED ALWAYS AS(lower(btrim(specification_name))) STORED,created_at timestamptz NOT NULL DEFAULT now(),UNIQUE(target_parsed_id,specification_name,specification_value));
CREATE TABLE IF NOT EXISTS retail.target_unlocker_evidence(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),collection_run_id uuid REFERENCES retail.collection_runs(id),platform_id uuid NOT NULL REFERENCES retail.retail_platforms(id),target_url text NOT NULL,unlocker_zone text NOT NULL CHECK(unlocker_zone IN('tcds_web_unlocker','tcds_premium_unlocker')),content_type text,response_status integer NOT NULL DEFAULT 200,content_hash text NOT NULL UNIQUE,response_body text NOT NULL,captured_at timestamptz NOT NULL DEFAULT now(),evidence_metadata jsonb NOT NULL DEFAULT '{}');
CREATE INDEX IF NOT EXISTS ix_target_unlocker_url_time ON retail.target_unlocker_evidence(target_url,captured_at DESC);
COMMIT;
